import type { NextApiRequest, NextApiResponse } from 'next';
import { promises as fs } from 'fs';
import path from 'path';
import crypto from 'crypto';

const DATA_DIR = path.join(process.cwd(), 'data');
const USERS_PATH = path.join(DATA_DIR, 'users.json');

function verifyPassword(password: string, stored: string) {
  try {
    // prefer bcryptjs if installed
    // eslint-disable-next-line @typescript-eslint/no-var-requires
    const bcrypt = require('bcryptjs');
    return bcrypt.compareSync(password, stored);
  } catch (e) {
    const [salt, derived] = (stored || '').split(':');
    if (!salt || !derived) return false;
    const hash = crypto.scryptSync(password, salt, 64).toString('hex');
    try {
      return crypto.timingSafeEqual(Buffer.from(hash, 'hex'), Buffer.from(derived, 'hex'));
    } catch (err) {
      return false;
    }
  }
}

async function fileLogin(email: string, password: string) {
  let users: any[] = [];
  try {
    const raw = await fs.readFile(USERS_PATH, 'utf8');
    users = JSON.parse(raw);
  } catch (err) {
    users = [];
  }
  const user = users.find(u => u.email === email);
  if (!user) return { error: 'Invalid credentials' };
  const ok = verifyPassword(password, user.passwordHash);
  if (!ok) return { error: 'Invalid credentials' };
  return { user: { id: user.id, email: user.email, profile: user.profile } };
}

async function sqliteLogin(dbPath: string, email: string, password: string) {
  const db = new BetterSqlite3(dbPath);
  db.prepare('CREATE TABLE IF NOT EXISTS users (id TEXT PRIMARY KEY, email TEXT UNIQUE, passwordHash TEXT, profile TEXT, createdAt TEXT)').run();
  const row = db.prepare('SELECT id, email, passwordHash, profile FROM users WHERE email = ?').get(email);
  db.close();
  if (!row) return { error: 'Invalid credentials' };
  const ok = verifyPassword(password, row.passwordHash);
  if (!ok) return { error: 'Invalid credentials' };
  return { user: { id: row.id, email: row.email, profile: row.profile ? JSON.parse(row.profile) : null } };
}

export default async function handler(req: NextApiRequest, res: NextApiResponse) {
  if (req.method !== 'POST') return res.status(405).json({ error: 'Method not allowed' });
  const { email, password } = req.body || {};
  if (!email || !password) return res.status(400).json({ error: 'Missing email or password' });

  try {
    // attempt sqlite path if better-sqlite3 is installed at runtime
    try {
      // eslint-disable-next-line @typescript-eslint/no-var-requires
      const BetterSqlite3 = require('better-sqlite3');
      if (BetterSqlite3) {
        const dbPath = path.join(process.cwd(), 'data', 'app.db');
        const out = await sqliteLogin(dbPath, email, password);
        if ((out as any).error) return res.status(401).json({ error: (out as any).error });
        // set cookie
        const { signToken, cookieSerialize } = require('../../../lib/auth');
        const token = await signToken({ id: out.user.id, email: out.user.email });
        res.setHeader('Set-Cookie', cookieSerialize('sahipath_token', token, { httpOnly: true, path: '/', maxAge: 60 * 60 * 24 * 7 }));
        return res.json(out);
      }
    } catch (e) {
      // sqlite not available — fall through to file-based login
    }

    const out = await fileLogin(email, password);
    if ((out as any).error) return res.status(401).json({ error: (out as any).error });
    const { signToken, cookieSerialize } = require('../../../lib/auth');
    const token = await signToken({ id: out.user.id, email: out.user.email });
    res.setHeader('Set-Cookie', cookieSerialize('sahipath_token', token, { httpOnly: true, path: '/', maxAge: 60 * 60 * 24 * 7 }));
    return res.json(out);
  } catch (err: any) {
    console.error('login error', err?.message || err);
    return res.status(500).json({ error: err?.message || 'internal error' });
  }
}
